import{_ as a,o as r,c as o,af as t}from"./chunks/framework.BSym9njW.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01-deploy/index.md","filePath":"en/01-deploy/index.md","lastUpdated":1782210600000}'),n={name:"01-deploy/index.md"};function l(i,e,s,m,c,d){return r(),o("div",null,[...e[0]||(e[0]=[t(`<div align="center"><h1>01-Deploy</h1><strong>🚀 ROCm LLM Deployment in Practice</strong></div><div align="center"><p><em>Get started with LLM deployment on AMD GPUs from scratch</em></p><p><a href="/hello-rocm/en/">Back to Home</a> · <a href="/hello-rocm/zh/01-deploy/">中文</a></p></div><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>  This module provides comprehensive tutorials for deploying large language models on AMD GPUs. Whether you are a beginner or an experienced developer, you can quickly learn how to deploy and run LLMs on the ROCm platform through these tutorials.</p><p>  Since ROCm 7.10.0, ROCm supports seamless installation in Python virtual environments just like CUDA, significantly lowering the barrier for LLM deployment on AMD GPUs.</p><p>  This module uses <strong>Google Gemma 4</strong> (<code>gemma-4-E4B-it</code> primarily) as the example model by default, and also provides parallel tutorials for <strong>Qwen3</strong> as a reference. The directory structure is as follows:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>01-Deploy/</span></span>
<span class="line"><span>└── models/</span></span>
<span class="line"><span>    ├── Gemma4/           # Deployment tutorials with Gemma 4 as the primary model (recommended)</span></span>
<span class="line"><span>    ├── Qwen3/            # Qwen3 series deployment tutorials (reference/comparison)</span></span>
<span class="line"><span>    └── Qwen3.5/          # Qwen3.5 series deployment tutorials (new architecture reference)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="tutorial-list" tabindex="-1">Tutorial List <a class="header-anchor" href="#tutorial-list" aria-label="Permalink to &quot;Tutorial List&quot;">​</a></h2><h3 id="ubuntu-24-04-rocm-7-environment-setup-tutorial" tabindex="-1">Ubuntu 24.04 + ROCm 7 Environment Setup Tutorial <a class="header-anchor" href="#ubuntu-24-04-rocm-7-environment-setup-tutorial" aria-label="Permalink to &quot;Ubuntu 24.04 + ROCm 7 Environment Setup Tutorial&quot;">​</a></h3><p>  This tutorial walks you through installing and verifying ROCm 7.1.0 on Ubuntu 24.04 step by step, including uninstalling old ROCm environments, running the official script to install ROCm, and using tools like <code>rocminfo</code> / <code>rocm-smi</code> / <code>amd-smi</code> to confirm GPU and driver status. It is recommended to complete this tutorial before starting any deployment tutorial.</p><ul><li><strong>Target Audience</strong>: Users setting up a ROCm environment on an AMD GPU for the first time</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 1 hour</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/env-prepare-ubuntu24-rocm7">Start the Environment Setup Tutorial (Gemma4)</a><br> 📎 Reference: <a href="/hello-rocm/en/01-deploy/qwen3/env-prepare-ubuntu24-rocm7">Qwen3 Version</a> · <a href="/hello-rocm/en/01-deploy/qwen3.5/env-prepare-ubuntu24-rocm7">Qwen3.5 Version</a></p><hr><h3 id="gemma-4-model-introduction" tabindex="-1">Gemma 4 Model Introduction <a class="header-anchor" href="#gemma-4-model-introduction" aria-label="Permalink to &quot;Gemma 4 Model Introduction&quot;">​</a></h3><p>  Before starting deployment, it is recommended to read the Gemma 4 model introduction to understand the architecture characteristics, capability differences, and hardware selection recommendations for the four versions: Gemma 4 E2B / E4B / 31B / 26B A4B, so you can choose the right model for your environment.</p><ul><li><strong>Target Audience</strong>: Users trying Gemma 4 for the first time</li><li><strong>Difficulty Level</strong>: ⭐</li><li><strong>Estimated Time</strong>: 15 minutes</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/gemma4_model">Read the Gemma 4 Model Introduction</a></p><hr><h3 id="lm-studio-llm-deployment-from-scratch" tabindex="-1">LM Studio LLM Deployment from Scratch <a class="header-anchor" href="#lm-studio-llm-deployment-from-scratch" aria-label="Permalink to &quot;LM Studio LLM Deployment from Scratch&quot;">​</a></h3><p>  LM Studio is a user-friendly desktop application that supports running large language models locally. This tutorial uses <strong>Gemma 4 E4B-it Q4_K_M</strong> as an example to guide you through deploying and running LLMs on AMD GPUs using LM Studio with the ROCm version of the llama.cpp backend.</p><ul><li><strong>Target Audience</strong>: Beginners and users who want to quickly experience LLMs</li><li><strong>Difficulty Level</strong>: ⭐</li><li><strong>Estimated Time</strong>: 30 minutes</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/lm-studio-rocm7-deploy">Start the LM Studio Deployment Tutorial (Gemma4)</a><br> 📎 Reference: <a href="/hello-rocm/en/01-deploy/qwen3/lm-studio-rocm7-deploy">Qwen3 Version</a> · <a href="/hello-rocm/en/01-deploy/qwen3.5/lm-studio-rocm7-deploy">Qwen3.5 Version</a></p><hr><h3 id="vllm-llm-deployment-from-scratch" tabindex="-1">vLLM LLM Deployment from Scratch <a class="header-anchor" href="#vllm-llm-deployment-from-scratch" aria-label="Permalink to &quot;vLLM LLM Deployment from Scratch&quot;">​</a></h3><p>  vLLM is a high-performance LLM inference and serving framework that supports efficient PagedAttention and continuous batching. This tutorial uses <strong>Gemma 4 E4B-it</strong> as an example, covering both a quick start method using the official ROCm vLLM Docker image, and an advanced method for manually compiling Triton / FlashAttention / vLLM from source.</p><ul><li><strong>Target Audience</strong>: Developers who need to set up inference services</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 1 hour</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/vllm-rocm7-deploy">Start the vLLM Deployment Tutorial (Gemma4)</a><br> 📎 Reference: <a href="/hello-rocm/en/01-deploy/qwen3/vllm-rocm7-deploy">Qwen3 Version</a> · <a href="/hello-rocm/en/01-deploy/qwen3.5/vllm-rocm7-deploy">Qwen3.5 Version</a></p><hr><h3 id="ollama-llm-deployment-from-scratch" tabindex="-1">Ollama LLM Deployment from Scratch <a class="header-anchor" href="#ollama-llm-deployment-from-scratch" aria-label="Permalink to &quot;Ollama LLM Deployment from Scratch&quot;">​</a></h3><p>  Ollama is a framework for quickly serving large language models and vision-language models with an efficient backend runtime. This tutorial uses <strong>Gemma 4 E4B-it Q4_K_M</strong> as an example to guide you through deploying LLMs on AMD GPUs using Ollama (ROCm version llama.cpp backend), with tokens/s benchmark examples included.</p><ul><li><strong>Target Audience</strong>: Developers who want to spin up a local inference service with a single command</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 1 hour</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/ollama-rocm7-deploy">Start the Ollama Deployment Tutorial (Gemma4)</a><br> 📎 Reference: <a href="/hello-rocm/en/01-deploy/qwen3/ollama-rocm7-deploy">Qwen3 Version</a> · <a href="/hello-rocm/en/01-deploy/qwen3.5/ollama-rocm7-deploy">Qwen3.5 Version</a></p><hr><h3 id="llama-cpp-llm-deployment-from-scratch" tabindex="-1">llama.cpp LLM Deployment from Scratch <a class="header-anchor" href="#llama-cpp-llm-deployment-from-scratch" aria-label="Permalink to &quot;llama.cpp LLM Deployment from Scratch&quot;">​</a></h3><p>  llama.cpp is a lightweight and high-performance inference backend that supports multiple model formats including GGUF, with optimized versions available for ROCm. This tutorial uses <strong>Gemma 4 E4B-it Q4_K_M (GGUF)</strong> as an example, showing how to deploy mainstream models on Ubuntu 24.04 + ROCm 7+ using both pre-built binaries and Docker.</p><ul><li><strong>Target Audience</strong>: Developers who want to freely orchestrate inference workflows via CLI / REST API</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 1.5 hours</li></ul><p>📖 <a href="/hello-rocm/en/01-deploy/gemma4/llamacpp-rocm7-deploy">Start the llama.cpp Deployment Tutorial (Gemma4)</a><br> 📎 Reference: <a href="/hello-rocm/en/01-deploy/qwen3/llamacpp-rocm7-deploy">Qwen3 Version</a> · <a href="/hello-rocm/en/01-deploy/qwen3.5/llamacpp-rocm7-deploy">Qwen3.5 Version</a></p><hr><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="hardware-requirements" tabindex="-1">Hardware Requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware Requirements&quot;">​</a></h3><ul><li>AMD GPU (ROCm-supported GPUs such as RX 7000 / 9000 series, Ryzen AI MAX / AI 300, Instinct MI series, etc.)</li><li>At least 8GB VRAM recommended (Gemma 4 E4B Q4_K_M quantized version can run with 8GB VRAM; for native bfloat16 inference or larger models, please refer to the VRAM recommendations in the corresponding tutorials)</li></ul><h3 id="software-requirements" tabindex="-1">Software Requirements <a class="header-anchor" href="#software-requirements" aria-label="Permalink to &quot;Software Requirements&quot;">​</a></h3><ul><li>Operating System: Linux (Ubuntu 22.04+) or Windows 11</li><li>ROCm 7.10.0 or higher</li><li>Python 3.10+</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Q: How do I check if my AMD GPU supports ROCm?</summary><p>Please refer to the <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm official support list</a> to check supported GPU models.</p></details><details><summary>Q: What should I do if I encounter a &quot;HIP error&quot; during deployment?</summary><ol><li>Confirm that ROCm is properly installed</li><li>Check that environment variables are correctly set</li><li>Try restarting the system and running again</li></ol></details><details><summary>Q: I get a permission denied error when downloading Gemma 4?</summary><p>Gemma series models require you to first click <strong>Agree &amp; Access</strong> on the corresponding model page on Hugging Face (e.g., <a href="https://huggingface.co/google/gemma-4-E4B-it">google/gemma-4-E4B-it</a>), then log in with a Hugging Face Token that has <code>read</code> permissions or inject it via <code>HF_TOKEN</code> into the container / process.</p></details><h2 id="reference-resources" tabindex="-1">Reference Resources <a class="header-anchor" href="#reference-resources" aria-label="Permalink to &quot;Reference Resources&quot;">​</a></h2><ul><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm Official Documentation</a></li><li><a href="https://docs.vllm.ai/" target="_blank" rel="noreferrer">vLLM Official Documentation</a></li><li><a href="https://docs.ollama.com/" target="_blank" rel="noreferrer">Ollama Official Documentation</a></li><li><a href="https://github.com/ggerganov/llama.cpp" target="_blank" rel="noreferrer">llama.cpp Repository</a></li><li><a href="https://huggingface.co/collections/google/gemma-4" target="_blank" rel="noreferrer">Hugging Face Gemma 4 Model Collection</a></li></ul><hr><div align="center"><p><strong>Contributions for more deployment tutorials are welcome!</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">Submit an Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">Submit a PR</a></p></div>`,51)])])}const h=a(n,[["render",l]]);export{p as __pageData,h as default};
